const orders = [{id: 1, customerId: 10}];
const customers = [{id: 10, name: 'Alice'}];
const denormalize = (o) => ({...o, customerName: 'Alice'});
console.log(denormalize(orders[0]));

orders = [{'id': 1, 'cust_id': 10}]
customers = {'10': 'Alice'}
for order in orders:
    order['cust_name'] = customers['10']

class Order {
    int id, customerId;
    String customerName;
}

ALTER TABLE orders ADD COLUMN customer_name VARCHAR(100);
UPDATE orders o
SET customer_name = c.name
FROM customers c WHERE o.customer_id = c.id;
